    @Override
    public void close() {
        gui_to_var();
        root.getSetup().setLocalConfig(CONFIG_BANK_CASH + mainwin.getAZ().title, jTBankCash.getText().trim());
        // save date-only ISO format (same pattern as Operational/BookingLines)
        String fromDate = jDateFrom.getDate();
        root.getSetup().setLocalConfig(CONFIG_DATE_FROM + mainwin.getAZ().title, fromDate != null && fromDate.length() >= 10 ? fromDate.substring(0, 10) : fromDate);
        String tillDate = jDateTill.getDate();
        root.getSetup().setLocalConfig(CONFIG_DATE_TILL + mainwin.getAZ().title, tillDate != null && tillDate.length() >= 10 ? tillDate.substring(0, 10) : tillDate);
        // AI-modified end
        root.getSetup().setLocalConfig(CONFIG_CAT_INCOME + mainwin.getAZ().title, String.valueOf(jCBCatIncome.isSelected()));
        root.getSetup().setLocalConfig(CONFIG_CAT_EXPENSE + mainwin.getAZ().title, String.valueOf(jCBCatExpense.isSelected()));
        root.getSetup().setLocalConfig(CONFIG_CAT_LIABILITY + mainwin.getAZ().title, String.valueOf(jCBCatLiability.isSelected()));
        super.close();
    }

    private double parseBankCash() {
        try {
            return Double.parseDouble(jTBankCash.getText().trim().replace(",", "."));
        } catch (NumberFormatException e) {
            return 0.0;
        }
    }

    /**
     * Build the set of selected Category values from the checkboxes.
     * INCOME and EXPENSE enabled by default.
     */
    private Set<DBAccountClasses.Category> buildCategoryFilter() {
        Set<DBAccountClasses.Category> filter = EnumSet.noneOf(DBAccountClasses.Category.class);
        if (jCBCatIncome.isSelected()) filter.add(DBAccountClasses.Category.INCOME);
        if (jCBCatExpense.isSelected()) filter.add(DBAccountClasses.Category.EXPENSE);
        if (jCBCatLiability.isSelected()) filter.add(DBAccountClasses.Category.LIABILITY);
        return filter;
    }

    private void generateReport() {
        new AutoMBox(getTitle()) {
            @Override
            public void do_stuff() throws Exception {
                setWaitCursor();
                gui_to_var();
                double bankCash = parseBankCash();
                Set<DBAccountClasses.Category> categoryFilter = buildCategoryFilter();
                ReportCashFlowRenderer renderer =
                        new ReportCashFlowRenderer(getTransaction(), mainwin.getAZ(), bankCash, dateFrom, dateTill, categoryFilter);
                renderer.collectData();
                jReport.setText(renderer.render());
                jReport.setCaretPosition(0);
                setWaitCursor(false);
            }
        };
    }

